# Instructions ----
#' This file follows the format generated by FIMS:::use_testthat_template().
#' Necessary tests include input and output (IO) correctness [IO
#' correctness], edge-case handling [Edge handling], and built-in errors and
#' warnings [Error handling]. See `?FIMS:::use_testthat_template` for more
#' information. Every test should have a @description tag, which can only span
#' one lines, that will be used in the bookdown report of the results from
#' {testthat}. This line can be more than 80 characters.

# setup_default_data_index_landings ----
## Setup ----
data <- FIMS::FIMSFrame(data_big)
source_row <- get_data(data) |>
  dplyr::filter(.data[["type"]] %in% c("index", "landings")) |>
  dplyr::slice(1)
fleet <- source_row[["name"]]
module_type <- FIMS:::snake_to_pascal(source_row[["type"]])

## IO correctness ----
test_that("`setup_default_data_index_landings()` works with correct inputs", {
  result <- setup_default_data_index_landings(
    data = data,
    fleet = fleet,
    module_type = module_type
  )

  #' @description Test that output is a `tbl_df` with Data module fields.
  expect_s3_class(result, "tbl_df")
  expect_true(all(result[["module_name"]] == "Data"))

  #' @description Test that returned rows map to the requested fleet and module type.
  expect_true(all(result[["fleet"]] == fleet))
  expect_true(all(result[["module_type"]] == module_type))

  clear()
})

## Edge handling ----
test_that("`setup_default_data_index_landings()` works with edge cases", {
  result_dnorm <- setup_default_data_index_landings(
    data = data,
    fleet = fleet,
    module_type = module_type,
    distribution = "Dnorm"
  )

  #' @description Test that choosing Dnorm updates the distribution label.
  expect_true(all(result_dnorm[["distribution"]] == "Dnorm"))

  clear()
})

## Error handling ----
test_that("`setup_default_data_index_landings()` returns correct error messages", {
  #' @description Test that invalid fleet type returns expected error.
  expect_error(
    object = setup_default_data_index_landings(data = data, fleet = 1, module_type = module_type),
    regexp = "fleet"
  )

  #' @description Test that unavailable module type for a fleet returns expected error.
  expect_error(
    object = setup_default_data_index_landings(data = data, fleet = fleet, module_type = "AgeComp"),
    regexp = "should be one of|must be one of"
  )

  clear()
})
